                    <p className="text-slate-500 mt-0.5 text-sm">All 13 dimensions sorted by {dimPerfSortBy === 'score' ? `${companyName}${companyName.endsWith('s') ? "'" : "'s"} score` : dimPerfSortBy === 'benchmark' ? 'benchmark score' : 'employee priority weight'}</p>
